   460→## 5. Performance Optimizations
   461→
   462→### 5.1 RBush Spatial Index
   463→
   464→**File:** `apps/canvas/src/spatial/RBushSpatialIndex.ts`
   465→
   466→```typescript
   467→export class RBushSpatialIndex implements ISpatialIndex {
   468→  private tree: RBush<RBushItem>;
   469→  private itemsById: Map<string, RBushItem> = new Map();
   470→
   471→  load(items: SpatialItem[]): void {
   472→    const startTime = performance.now();
   473→
   474→    this.tree.clear();
   475→    this.itemsById.clear();
   476→
   477→    for (const item of items) {
   478→      this.itemsById.set(item.id, item as RBushItem);
   479→    }
   480→
   481→    this.tree.load(items as RBushItem[]); // Bulk load is O(n log n)
   482→
   483→    // Performance: ~0.5ms for 60k items
   484→  }
   485→
   486→  queryViewport(bounds: ViewportBounds): string[] {
   487→    // O(log n + k) where k = result count
   488→    const results = this.tree.search({
   489→      minX: bounds.minX,
   490→      minY: bounds.minY,
   491→      maxX: bounds.maxX,
   492→      maxY: bounds.maxY,
   493→    });
   494→
   495→    return results.map(item => item.id);
   496→  }
   497→
   498→  queryNearest(x: number, y: number, maxDistance?: number): SpatialQueryResult | null {
   499→    // Expanding radius search
   500→    let radius = 50;
   501→    while (radius <= maxRadius && nearest === null) {
   502→      const candidates = this.tree.search({
   503→        minX: x - radius,
   504→        minY: y - radius,
   505→        maxX: x + radius,
   506→        maxY: y + radius,
   507→      });
   508→
   509→      for (const item of candidates) {
   510→        const dist = distanceToCenter(x, y, item);
   511→        if (dist < minDist && dist <= maxRadius) {
   512→          minDist = dist;
   513→          nearest = { id: item.id, distance: dist };
   514→        }
   515→      }
   516→
   517→      radius *= 2;
   518→    }
   519→
   520→    return nearest;
   521→  }
   522→}
   523→```
