### MOMENTUM ALGORITHM

```typescript
const startMomentum = useCallback(() => {
  const { vx, vy } = calculateAverageVelocity();

  canvasStore.dispatch(canvasActions.viewport.startMomentum({
    velocityX: vx * 16, // Convert to world units per frame
    velocityY: vy * 16,
  }));

  const animate = () => {
    const state = canvasStore.getState();
    const { velocityX, velocityY, isActive } = state.viewport.momentum;

    if (!isActive) return;

    // Apply friction
    const newVelX = velocityX * MOMENTUM_FRICTION;
    const newVelY = velocityY * MOMENTUM_FRICTION;

    // Check velocity threshold
    if (Math.abs(newVelX) < MOMENTUM_MIN_VELOCITY &&
        Math.abs(newVelY) < MOMENTUM_MIN_VELOCITY) {
      canvasStore.dispatch(canvasActions.viewport.stopMomentum());
      return;
    }

    // Update camera position
    const newCamera = clampCameraToWorld(
      camera.x + newVelX,
      camera.y + newVelY,
      zoom
    );

    canvasStore.dispatch(canvasActions.viewport.updateMomentum({
      velocityX: newVelX,
      velocityY: newVelY,
      camera: newCamera,
    }));

    requestAnimationFrame(animate);
  };

  requestAnimationFrame(animate);
}, []);
```

### EASING FUNCTIONS

