   137→
   138→interface UserData {
   139→  id: string;
   140→  name: string;
   141→  email: string;
   142→}
   143→
   144→const userSlice = createAsyncSlice({
   145→  id: 'user',
   146→
   147→  // Async load function
   148→  load: async (userId: string, context: { apiClient: ApiClient }) => {
   149→    const response = await context.apiClient.get(`/users/${userId}`);
   150→    return response.data as UserData;
   151→  },
   152→
   153→  // Context required by load function
   154→  context: {
   155→    apiClient: null as unknown as ApiClient,  // Provided at runtime
   156→  },
   157→
   158→  // Optional initial async state override
   159→  initial: {
   160→    loading: false,
   161→    loaded: false,
   162→    failed: false,
   163→    error: null,
   164→    value: null,
   165→    changes: 0,
   166→  },
   167→
   168→  cache: { policy: 'private', ttl: '5m' },
