### 2.2.5 Usage Patterns

**Pattern 1: React Component with Selector**

```typescript
// Components that need reactive state updates
import { useCanvasSelector, canvasActions, canvasStore } from '../state';

function ZoomControls() {
  // Reactive - component re-renders when zoom changes
  const zoom = useCanvasSelector(s => s.viewport.camera.zoom);

  const handleZoomIn = () => {
    canvasStore.dispatch(canvasActions.viewport.setZoom(zoom * 1.2));
  };

  const handleZoomOut = () => {
    canvasStore.dispatch(canvasActions.viewport.setZoom(zoom / 1.2));
  };

  return (
    <div>
      <button onClick={handleZoomOut}>-</button>
      <span>{Math.round(zoom * 100)}%</span>
      <button onClick={handleZoomIn}>+</button>
    </div>
