**Pattern 2: Animation Loop (NO React Hooks)**

```typescript
// Animation loops MUST use store.getState() directly
// NEVER use React hooks in animation loops (stale closures!)
import { useFrame } from '@react-three/fiber';
import { canvasStore, canvasActions } from '../state';

function CameraAnimator() {
  useFrame(() => {
    // CORRECT: Get fresh state every frame
    const state = canvasStore.getState();
    const { animation, camera } = state.viewport;

    if (!animation.isAnimating) return;

    const elapsed = Date.now() - animation.startTime;
    const progress = Math.min(elapsed / animation.duration, 1);
    const eased = easeOutCubic(progress);

    const newCamera = {
      x: lerp(animation.startX, animation.targetX, eased),
      y: lerp(animation.startY, animation.targetY, eased),
      zoom: lerp(animation.startZoom, animation.targetZoom, eased),
    };

    canvasStore.dispatch(canvasActions.viewport.updateAnimation({
      camera: newCamera
    }));

    if (progress >= 1) {
      canvasStore.dispatch(canvasActions.viewport.stopAnimation());
    }
  });

  return null;
}

function lerp(a: number, b: number, t: number): number {
  return a + (b - a) * t;
}

function easeOutCubic(t: number): number {
  return 1 - Math.pow(1 - t, 3);
}
```

**Pattern 3: Event Handler with Direct Store Access**

```typescript
// Event handlers that need immediate state
const handleWheel = useCallback((event: WheelEvent) => {
  event.preventDefault();

  // Get current state synchronously
  const state = canvasStore.getState();
  const { camera } = state.viewport;

  // Calculate new zoom
  const zoomDelta = -event.deltaY * ZOOM_SENSITIVITY;
  const newZoom = clamp(camera.zoom * (1 + zoomDelta), MIN_ZOOM, MAX_ZOOM);

  // Dispatch update
  canvasStore.dispatch(canvasActions.viewport.setCamera({
    x: camera.x,
    y: camera.y,
    zoom: newZoom,
  }));
}, []);
```

### 2.2.6 metadata: false Explained

**Why this option is critical for 60fps:**

When `metadata: true` (default), every dispatch creates:
```typescript
{
  changes: previousChanges + 1,
  updatedAt: Date.now(),
  updatedByActionType: action.type,
  sessionID: '...',
  userID: '...',
}
```

At 60fps with continuous updates:
- 60 new objects allocated per second
- Increases GC pressure
- Mobile devices especially sensitive
- Can cause frame drops during GC pause

With `metadata: false`:
- No per-dispatch allocations
- State updates are direct Immer mutations
- GC pressure eliminated for state updates

