## 2.2 State Management

### 2.2.1 Library Overview

**Package:** `@zazcart/tools` (located at `packages/toolkit`)

The library provides a slice-based state machine pattern (NOT FSM/XState style) with:
- Immer-powered immutable updates
- React 18 `useSyncExternalStore` integration
- Zero-allocation option for 60fps updates

**Critical Note:** `@zazcart/tools` and `@belt/tools` are the SAME library (same GitHub repo, different npm names). No API migration required.

### 2.2.2 createMachine Pattern

The central state machine combines all slices:

```typescript
// File: apps/canvas/src/state/canvas-machine.ts
import { createMachine } from '@zazcart/tools';
import { viewportSlice } from './viewport';
import { interactionSlice } from './interaction';

export const canvasMachine = createMachine({
  // Unique machine identifier
  id: 'canvas',

  // State slices to combine
  slices: {
    viewport: viewportSlice,
    interaction: interactionSlice,
  },

  // Global context (shared across slices)
  context: {
    userID: null,  // Canvas is public/anonymous
  },

  // CRITICAL: Disable metadata tracking for 60fps
  // Prevents per-dispatch object allocations that trigger GC
  metadata: false,
});

// Typed React hooks
export const useCanvas = canvasMachine.useMachine;
export const useCanvasSelector = canvasMachine.useSelector;

// Action creators (organized by slice)
export const canvasActions = canvasMachine.actions;

// Direct store access (for animation loops - NO React re-renders)
export const canvasStore = {
  getState: canvasMachine.getState,
  dispatch: canvasMachine.dispatch,
  subscribe: canvasMachine.subscribe,
};
```

### 2.2.3 createSyncSlice Pattern

Each state domain is a separate slice:

```typescript
// File: apps/canvas/src/state/viewport.ts
import { createSyncSlice } from '@zazcart/tools';

// Types
export interface CameraPosition {
  x: number;
  y: number;
  zoom: number;
}

export interface MomentumState {
  velocityX: number;
  velocityY: number;
  isActive: boolean;
}

export interface AnimationState {
  isAnimating: boolean;
  startTime: number;
  duration: number;
  startX: number;
  startY: number;
  startZoom: number;
  targetX: number;
  targetY: number;
  targetZoom: number;
}

export interface ViewportSliceState {
  camera: CameraPosition;
  canvasSize: { width: number; height: number };
  isInitialized: boolean;
  momentum: MomentumState;
  animation: AnimationState;
  isPanning: boolean;
  panStart: CameraPosition;
  cameraPosAtPanStart: CameraPosition;
}

// Initial state
const initialState: ViewportSliceState = {
  camera: { x: 0, y: 0, zoom: 1 },
  canvasSize: { width: 0, height: 0 },
  isInitialized: false,
  momentum: { velocityX: 0, velocityY: 0, isActive: false },
  animation: {
    isAnimating: false,
    startTime: 0,
    duration: 250,
    startX: 0, startY: 0, startZoom: 1,
    targetX: 0, targetY: 0, targetZoom: 1,
  },
  isPanning: false,
  panStart: { x: 0, y: 0, zoom: 1 },
  cameraPosAtPanStart: { x: 0, y: 0, zoom: 1 },
};

// Slice definition
export const viewportSlice = createSyncSlice({
  id: 'viewport',
  initial: initialState,

  // Cache strategy (session = resets on page refresh)
  cache: { policy: 'session' },

  // Reducers (Immer draft - "mutable" syntax internally immutable)
  reducers: {
    setCamera(state, payload: CameraPosition) {
      state.camera = payload;
    },

    setZoom(state, payload: number) {
      state.camera.zoom = payload;
    },

    setCanvasSize(state, payload: { width: number; height: number }) {
      state.canvasSize = payload;
      state.isInitialized = true;
    },

    startPan(state, payload: { x: number; y: number }) {
      state.isPanning = true;
      state.panStart = { x: payload.x, y: payload.y, zoom: state.camera.zoom };
      state.cameraPosAtPanStart = { ...state.camera };
    },

    endPan(state) {
      state.isPanning = false;
    },

    startMomentum(state, payload: { velocityX: number; velocityY: number }) {
      state.momentum = {
        velocityX: payload.velocityX,
        velocityY: payload.velocityY,
        isActive: true,
      };
    },

    updateMomentum(state, payload: {
      velocityX: number;
      velocityY: number;
      camera: CameraPosition
    }) {
      state.momentum.velocityX = payload.velocityX;
      state.momentum.velocityY = payload.velocityY;
      state.camera = payload.camera;
    },

    stopMomentum(state) {
      state.momentum.isActive = false;
      state.momentum.velocityX = 0;
      state.momentum.velocityY = 0;
    },

    startAnimation(state, payload: {
      targetX: number;
      targetY: number;
      targetZoom: number;
      duration?: number;
    }) {
      state.animation = {
        isAnimating: true,
        startTime: Date.now(),
        duration: payload.duration ?? 250,
        startX: state.camera.x,
        startY: state.camera.y,
        startZoom: state.camera.zoom,
        targetX: payload.targetX,
        targetY: payload.targetY,
        targetZoom: payload.targetZoom,
      };
    },

    updateAnimation(state, payload: { camera: CameraPosition }) {
      state.camera = payload.camera;
    },

    stopAnimation(state) {
      state.animation.isAnimating = false;
    },

    // Reset to default
    reset() {
      return initialState;
    },
  },
});
```

