function ZoomControls() {
  // Reactive - component re-renders when zoom changes
  const zoom = useCanvasSelector(s => s.viewport.camera.zoom);

  const handleZoomIn = () => {
    canvasStore.dispatch(canvasActions.viewport.setZoom(zoom * 1.2));
  };

