// Camera position is managed via state, synced to Three.js camera
function CameraController() {
  const camera = useThree((state) => state.camera);
  const { camera: cameraState } = useCanvasSelector(s => s.viewport);

  // Sync state to Three.js camera
  useFrame(() => {
    if (camera instanceof OrthographicCamera) {
      camera.position.x = cameraState.x;
      camera.position.y = cameraState.y;
      camera.zoom = cameraState.zoom;
      camera.updateProjectionMatrix();
    }
  });

  return null;
}
